                    if (item_Audience.ValueKind == JsonValueKind.String &&
                        item_Audience.GetString().ToNullIfEmpty() is { } si_Audience)
                    {
                        list_Audience.Add(si_Audience);
                    }
                }
                if (list_Audience.Count > 0)
                    ctx.Audience = list_Audience;
            }
        }
        if (payload.TryGetProperty("d2_session_id", out var el_SessionId))
        {
            if (el_SessionId.ValueKind == JsonValueKind.String &&
                el_SessionId.GetString().TryParseTruthyNull(out Guid? v_SessionId))
            {
                ctx.SessionId = v_SessionId;
            }
        }
        if (payload.TryGetProperty("iat", out var el_TokenIssuedAt))
        {
            if (el_TokenIssuedAt.ValueKind == JsonValueKind.Number &&
                el_TokenIssuedAt.TryGetInt64(out var v_TokenIssuedAt))
            {
                ctx.TokenIssuedAt = DateTimeOffset.FromUnixTimeSeconds(v_TokenIssuedAt);
            }
            else if (el_TokenIssuedAt.ValueKind == JsonValueKind.String &&
                DateTimeOffset.TryParse(el_TokenIssuedAt.GetString(), out var vs_TokenIssuedAt))
            {
                ctx.TokenIssuedAt = vs_TokenIssuedAt;
            }
        }
        if (payload.TryGetProperty("exp", out var el_TokenExpiresAt))
        {
            if (el_TokenExpiresAt.ValueKind == JsonValueKind.Number &&
                el_TokenExpiresAt.TryGetInt64(out var v_TokenExpiresAt))
            {
                ctx.TokenExpiresAt = DateTimeOffset.FromUnixTimeSeconds(v_TokenExpiresAt);
            }
            else if (el_TokenExpiresAt.ValueKind == JsonValueKind.String &&
                DateTimeOffset.TryParse(el_TokenExpiresAt.GetString(), out var vs_TokenExpiresAt))
            {
                ctx.TokenExpiresAt = vs_TokenExpiresAt;
            }
        }
        if (payload.TryGetProperty("act", out var el_ActorChain))
        {
            ctx.ActorChain = ActorChainParser.ParseFromJson(el_ActorChain);
        }
        if (payload.TryGetProperty("amr", out var el_AuthMethod))
        {
            if (el_AuthMethod.ValueKind == JsonValueKind.String)
            {
                ctx.AuthMethod = el_AuthMethod.GetString().ToNullIfEmpty();
            }
        }
        if (payload.TryGetProperty("d2_step_up_at", out var el_LastStepUpAt))
        {
            if (el_LastStepUpAt.ValueKind == JsonValueKind.Number &&
                el_LastStepUpAt.TryGetInt64(out var v_LastStepUpAt))
            {
                ctx.LastStepUpAt = DateTimeOffset.FromUnixTimeSeconds(v_LastStepUpAt);
            }
            else if (el_LastStepUpAt.ValueKind == JsonValueKind.String &&
                DateTimeOffset.TryParse(el_LastStepUpAt.GetString(), out var vs_LastStepUpAt))
            {
                ctx.LastStepUpAt = vs_LastStepUpAt;
            }
        }
        if (payload.TryGetProperty("sub", out var el_Subject))
        {
            if (el_Subject.ValueKind == JsonValueKind.String)
            {
                ctx.Subject = el_Subject.GetString().ToNullIfEmpty();
            }
        }
        if (payload.TryGetProperty("sub", out var el_UserId))
        {
            if (el_UserId.ValueKind == JsonValueKind.String &&
                el_UserId.GetString().TryParseTruthyNull(out Guid? v_UserId))
            {
                ctx.UserId = v_UserId;
            }
        }
        if (payload.TryGetProperty("d2_username", out var el_Username))
        {
            if (el_Username.ValueKind == JsonValueKind.String)
            {
                ctx.Username = el_Username.GetString().ToNullIfEmpty();
            }
        }
        if (payload.TryGetProperty("client_id", out var el_RequestedByClientId))
        {
            if (el_RequestedByClientId.ValueKind == JsonValueKind.String)
            {
                ctx.RequestedByClientId = el_RequestedByClientId.GetString().ToNullIfEmpty();
            }
        }
        if (payload.TryGetProperty("d2_org_id", out var el_OrgId))
        {
            if (el_OrgId.ValueKind == JsonValueKind.String &&
                el_OrgId.GetString().TryParseTruthyNull(out Guid? v_OrgId))
            {
                ctx.OrgId = v_OrgId;
            }
        }
        if (payload.TryGetProperty("d2_org_name", out var el_OrgName))
        {
            if (el_OrgName.ValueKind == JsonValueKind.String)
            {
                ctx.OrgName = el_OrgName.GetString().ToNullIfEmpty();
            }
        }
        if (payload.TryGetProperty("d2_org_type", out var el_OrgType))
        {
            if (el_OrgType.ValueKind == JsonValueKind.String &&
                el_OrgType.GetString().TryParseTruthyNull<OrgType>(out var v_OrgType))
            {
                ctx.OrgType = v_OrgType;
            }
        }
        if (payload.TryGetProperty("d2_org_role", out var el_OrgRole))
        {
            if (el_OrgRole.ValueKind == JsonValueKind.String &&
                el_OrgRole.GetString().TryParseTruthyNull<Role>(out var v_OrgRole))
            {
                ctx.OrgRole = v_OrgRole;
            }
        }
        if (payload.TryGetProperty("scope", out var el_Scopes))
        {
            ctx.Scopes = ScopeClaimParser.Parse(el_Scopes);
        }
        if (payload.TryGetProperty("d2_fp", out var el_SessionFingerprint))
        {
            if (el_SessionFingerprint.ValueKind == JsonValueKind.String)
            {
                ctx.SessionFingerprint = el_SessionFingerprint.GetString().ToNullIfEmpty();
            }
        }
        return ctx;
    }

    /// <summary>
    /// Builds a <see cref="MutableRequestContext"/> from an authenticated
    /// <see cref="ClaimsPrincipal"/> (typical AspNetCore JWT path). Sets only
    /// auth-derived fields; transport-level fields require their respective
    /// filling extensions to populate.
    /// </summary>
    /// <remarks>
    /// Trusts that the auth middleware has already validated signature, expiry,
    /// audience, and issuer before constructing the ClaimsPrincipal — that's the
    /// AspNetCore authentication middleware's contract.
    /// </remarks>
    /// <param name="principal">The authenticated principal.</param>
    /// <returns>A new mutable context with auth fields populated.</returns>
    public static MutableRequestContext FromClaims(ClaimsPrincipal principal)
    {
        var ctx = new MutableRequestContext();
        ctx.IsAuthenticated = principal.Identity?.IsAuthenticated ?? false;
        var claims_Audience = principal.FindAll("aud")
            .Select(c => c.Value.ToNullIfEmpty())
            .Where(v => v is not null)
            .Cast<string>()
            .ToList();
        if (claims_Audience.Count > 0)
        {
            ctx.Audience = claims_Audience;
        }
        var claim_SessionId = principal.FindFirst("d2_session_id")?.Value;
        if (claim_SessionId is not null)
        {
            if (claim_SessionId.TryParseTruthyNull(out Guid? v_SessionId))
            {
                ctx.SessionId = v_SessionId;
            }
        }
        var claim_TokenIssuedAt = principal.FindFirst("iat")?.Value;
        if (claim_TokenIssuedAt is not null)
        {
            if (long.TryParse(claim_TokenIssuedAt, out var ts_TokenIssuedAt))
            {
                ctx.TokenIssuedAt = DateTimeOffset.FromUnixTimeSeconds(ts_TokenIssuedAt);
            }
            else if (DateTimeOffset.TryParse(claim_TokenIssuedAt, out var vs_TokenIssuedAt))
            {
                ctx.TokenIssuedAt = vs_TokenIssuedAt;
            }
        }
        var claim_TokenExpiresAt = principal.FindFirst("exp")?.Value;
        if (claim_TokenExpiresAt is not null)
        {
            if (long.TryParse(claim_TokenExpiresAt, out var ts_TokenExpiresAt))
            {
                ctx.TokenExpiresAt = DateTimeOffset.FromUnixTimeSeconds(ts_TokenExpiresAt);
            }
            else if (DateTimeOffset.TryParse(claim_TokenExpiresAt, out var vs_TokenExpiresAt))
            {
                ctx.TokenExpiresAt = vs_TokenExpiresAt;
            }
        }
        var claim_ActorChain = principal.FindFirst("act")?.Value;
        if (claim_ActorChain is not null)
        {
            ctx.ActorChain = ActorChainParser.ParseFromJsonString(claim_ActorChain);
        }
        var claim_AuthMethod = principal.FindFirst("amr")?.Value;
        if (claim_AuthMethod is not null)
        {
            ctx.AuthMethod = claim_AuthMethod.ToNullIfEmpty();
        }
        var claim_LastStepUpAt = principal.FindFirst("d2_step_up_at")?.Value;
        if (claim_LastStepUpAt is not null)
        {
            if (long.TryParse(claim_LastStepUpAt, out var ts_LastStepUpAt))
            {
                ctx.LastStepUpAt = DateTimeOffset.FromUnixTimeSeconds(ts_LastStepUpAt);
            }
            else if (DateTimeOffset.TryParse(claim_LastStepUpAt, out var vs_LastStepUpAt))
            {
                ctx.LastStepUpAt = vs_LastStepUpAt;
            }
        }
        var claim_Subject = principal.FindFirst("sub")?.Value;
        if (claim_Subject is not null)
        {
            ctx.Subject = claim_Subject.ToNullIfEmpty();
        }
        var claim_UserId = principal.FindFirst("sub")?.Value;
        if (claim_UserId is not null)
        {
            if (claim_UserId.TryParseTruthyNull(out Guid? v_UserId))
            {
                ctx.UserId = v_UserId;
            }
        }
        var claim_Username = principal.FindFirst("d2_username")?.Value;
        if (claim_Username is not null)
        {
            ctx.Username = claim_Username.ToNullIfEmpty();
        }
        var claim_RequestedByClientId = principal.FindFirst("client_id")?.Value;
        if (claim_RequestedByClientId is not null)
        {
            ctx.RequestedByClientId = claim_RequestedByClientId.ToNullIfEmpty();
        }
        var claim_OrgId = principal.FindFirst("d2_org_id")?.Value;
        if (claim_OrgId is not null)
        {
            if (claim_OrgId.TryParseTruthyNull(out Guid? v_OrgId))
            {
                ctx.OrgId = v_OrgId;
            }
        }
        var claim_OrgName = principal.FindFirst("d2_org_name")?.Value;
        if (claim_OrgName is not null)
        {
            ctx.OrgName = claim_OrgName.ToNullIfEmpty();
        }
        var claim_OrgType = principal.FindFirst("d2_org_type")?.Value;
        if (claim_OrgType is not null)
        {
            if (claim_OrgType.TryParseTruthyNull<OrgType>(out var v_OrgType))
            {
                ctx.OrgType = v_OrgType;
            }
        }
        var claim_OrgRole = principal.FindFirst("d2_org_role")?.Value;
        if (claim_OrgRole is not null)
        {
            if (claim_OrgRole.TryParseTruthyNull<Role>(out var v_OrgRole))
            {
                ctx.OrgRole = v_OrgRole;
            }
        }
        var claim_Scopes = principal.FindFirst("scope")?.Value;
        if (claim_Scopes is not null)
        {
            ctx.Scopes = ScopeClaimParser.ParseString(claim_Scopes);
        }
        var claim_SessionFingerprint = principal.FindFirst("d2_fp")?.Value;
        if (claim_SessionFingerprint is not null)
        {
            ctx.SessionFingerprint = claim_SessionFingerprint.ToNullIfEmpty();
        }
        return ctx;
    }
